import type { FunctionComponent } from 'react';
import type { I18nBaseProps, PrimitiveType } from './common';

import { captureOwnerStack, createElement } from 'react';

import { createDeprecationLogger } from '@meli/deprecation';

const logDeprecated = /* #__PURE__*/ createDeprecationLogger('@nordic/i18n');

const REPLACEMENT_REGEX = /\{(\d+)\}/g;

/**
 * Replace expressions on given string based on placeholders like {0}
 */
const interpolate = (
  text: string,
  { tags, replacements = {} }: Pick<I18nWithTagsProps, 'replacements' | 'tags'>,
) =>
  text.replace(
    REPLACEMENT_REGEX,
    (match, index) => tags[+index] || `${replacements[+index] || match}`,
  );

export type I18nWithTagsProps = I18nBaseProps & {
  /**
   * HTML tags to replace the placeholders in the given text.
   *
   * @deprecated Use `values` prop instead.
   * @see {@link https://nordic.adminml.com/docs/migration-guides/modules/i18n/tags-and-components-to-values | Migration Guide}
   */
  tags: Record<number, string>;

  /**
   * Replace placeholders with given values.
   *
   * @deprecated Use `values` prop instead.
   * @see {@link https://nordic.adminml.com/docs/migration-guides/modules/i18n/tags-and-components-to-values | Migration Guide}
   */
  replacements?: Array<PrimitiveType> | Record<number, PrimitiveType>;
};

// TODO: Remove in next breaking
export const I18nWithTags: FunctionComponent<I18nWithTagsProps> = (props) => {
  if (__DEV__) {
    const stack = captureOwnerStack()!.split('\n');

    stack.shift();
    logDeprecated(
      '"tags" prop is deprecated. Use "values" prop instead. Refer to the migration guide: https://nordic.adminml.com/docs/migration-guides/modules/i18n/tags-and-components-to-values',
      { customStack: stack },
    );
  }

  const { text, tags, replacements, className, wrapper = 'div' } = props;

  return createElement(wrapper, {
    className,
    dangerouslySetInnerHTML: {
      __html: interpolate(text, { tags, replacements }),
    },
  });
};
